// ============================================================
// FIX: Parse Claude Message — soporta 3 formatos de mensaje
// A: bullets  "• _Label:_ valor"  (Legales)
// B: shortcodes ":red_circle: _Label_\ncontenido"  (Finance)
// C: emoji Unicode "🔍 Label\ncontenido"  (formato estándar)
// ============================================================
const rawText = $('Extract Event Data').item.json.message_text || '';
const text = rawText
  .replace(/<@[A-Z0-9]+\|[^>]+>/g, '')
  .replace(/<@[A-Z0-9]+>/g, '')
  .replace(/\*?Sent using\*?[^\n]*/g, '')
  .replace(/\*?Sent with\*?[^\n]*/g, '')
  .replace(/\*?Sent via\*?[^\n]*/g, '')
  .replace(/\*?Enviado[^\n]*/g, '')
  .trim();

const channel_id = $('Extract Event Data').item.json.channel_id || '';
const thread_ts  = $('Extract Event Data').item.json.thread_ts  || '';

const channelMap = {
  'C0AJ2599DA6': 'Finance & Accounting',
  'C0AJ67HK0ES': 'Legal & Compliance',
  'C0AK2PW5BGQ': 'Operations',
  'C0AKNPCNNSU': 'Sales & Partnerships',
  'C0AJMRFP0TD': 'Trading Desk',
  'C0ARDGP8134': 'Management'
};
const area = channelMap[channel_id] || '';

const extractBlock = (emojiLabel, bulletLabel, slackShortcodes) => {
  // Formato C: emoji Unicode bloque
  const emojiEscaped = emojiLabel.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const blockRegex = new RegExp(
    emojiEscaped + '\\s*\\n([\\s\\S]*?)(?=\\n:[a-z_]+:|\\n[\uD83D\uDD0D\uD83E\uDDED\u26A0\u2705\uD83D\uDEA8\uD83D\uDCCE\uD83D\uDC64]|$)',
    'i'
  );
  const blockMatch = text.match(blockRegex);
  if (blockMatch && blockMatch[1].trim()) return blockMatch[1].trim();

  // Formato B: shortcode de Slack bloque
  for (const sc of (slackShortcodes || [])) {
    const scEscaped = sc.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const scBlockRegex = new RegExp(
      scEscaped + '\\s*(?:_[^_]+_)?\\s*\\n([\\s\\S]*?)(?=\\n:[a-z_]+:|$)',
      'i'
    );
    const scMatch = text.match(scBlockRegex);
    if (scMatch && scMatch[1].trim()) return scMatch[1].trim();
  }

  // Formato A: bullet inline
  const bulletEscaped = bulletLabel.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const bulletRegex = new RegExp(
    '(?:\u2022\\s*_?' + bulletEscaped + ':?_?\\*?|\\*' + bulletEscaped + ':\\*)\\s*([^\\n]+)',
    'i'
  );
  const bulletMatch = text.match(bulletRegex);
  return bulletMatch ? bulletMatch[1].trim() : '';
};

const extractUrgencia = () => {
  const inline = text.match(/:(?:zap|rotating_light|alarm_clock)[^:]*:\s*_?Urgencia:?_?\s*([^\n]+)/i);
  if (inline) return inline[1].trim();
  const block = text.match(/:(?:zap|rotating_light|alarm_clock)[^:]*:\s*_?Urgencia_?\s*\n([^\n:]+)/i);
  if (block) return block[1].trim();
  const bullet = text.match(/[\u2022\-]\s*_?Urgencia:?_?\s*([^\n]+)/i);
  if (bullet) return bullet[1].trim();
  return '';
};

const solicitante = extractBlock('\uD83D\uDC64 Solicitante', 'Solicitante', [':bust_in_silhouette:']);
const problema    = extractBlock('\uD83D\uDD0D Problema',    'Problema',    [':red_circle:', ':mag:']);
const contexto    = extractBlock('\uD83E\uDDED Contexto',    'Contexto',    [':pushpin:', ':compass:']);
const impacto     = extractBlock('\u26A0\uFE0F Impacto',     'Impacto',     [':bar_chart:', ':warning:']);
const resultado   = extractBlock('\u2705 Resultado esperado','Resultado esperado', [':white_check_mark:']);
const urgencia    = extractUrgencia();

const problemaFull = problema;

const urgLower = (urgencia || '').toLowerCase();
let priority_id = '3';
if (urgLower.includes('cr\u00edtico') || urgLower.includes('critico')) priority_id = '1';
else if (urgLower.includes('alt')) priority_id = '2';
else if (urgLower.includes('bajo')) priority_id = '4';

const areaIdMap = {
  'Finance & Accounting': '10128',
  'Legal & Compliance':   '10129',
  'Operations':           '10130',
  'Sales & Partnerships': '10131',
  'Trading Desk':         '10132',
  'Management':           '10133'
};
const business_area_id = areaIdMap[area] || '';

const thread_url = 'https://arduasolutions.slack.com/archives/' + channel_id + '/p' + thread_ts.replace('.', '');

const rawSummary = '[Miles] ' + (area ? area + ' \u2014 ' : '') + problemaFull.replace(/\n/g, ' ');
const jira_summary = rawSummary.length > 150
  ? rawSummary.substring(0, rawSummary.lastIndexOf(' ', 150)) + '\u2026'
  : rawSummary;

return [{ json: {
  channel_id, thread_ts, area, solicitante,
  captured_area:      area,
  captured_contexto: contexto,
  captured_problema:  problemaFull,
  captured_impacto:   impacto,
  captured_resultado: resultado,
  captured_urgencia:  urgencia,
  priority_id, business_area_id, thread_url, jira_summary
}}];

const msgs = ($json.messages || []);
const thread_ts = $('Extract Event Data').item.json.thread_ts;
const milesAlreadyReplied = msgs.some(m => m.bot_id && m.ts !== thread_ts);
return [{ json: { ...$json, is_duplicate: milesAlreadyReplied } }];

// ============================================================================
// miles-conversation-handler · Check Approval Gate  (modelo capabilities)
// ----------------------------------------------------------------------------
// Resuelve, para el canal/area del requerimiento:
//   - approver_ids: TODOS los stakeholders del area con req.approve.own (a mencionar)
//   - needs_approval: false si el solicitante puede auto-aprobar
//       (tiene req.approve.own de su area  O  req.approve.cross)
//
// Fuentes:
//   Query Business Area     -> area (pageId + Name) desde el canal
//   Query Capabilities      -> Code -> pageId  (own, cross)
//   Query Area Stakeholders -> personas del area (con Capabilities[] + Slack ID)
//   Query Requester         -> el solicitante por Slack ID (Capabilities[] + Business Area[])
//
// Sin area configurada (canal sin fila en Business Areas) -> sin gate.
// ============================================================================

const CAP_OWN = 'req.approve.own';
const CAP_CROSS = 'req.approve.cross';

const channelId     = $('Extract Event Data').item.json.channel_id;
const solicitanteId = $('Extract Event Data').item.json.user_id || '';
const threadTs      = $('Extract Event Data').item.json.thread_ts;

// Campos normalizados del requerimiento (para el work-items-handler)
const pcm = $('Parse Claude Message').first().json;
const reqFields = {
  problema:           pcm.captured_problema   || pcm.problema   || '',
  contexto:           pcm.captured_contexto   || pcm.contexto   || '',
  impacto:            pcm.captured_impacto    || pcm.impacto    || '',
  resultado_esperado: pcm.captured_resultado  || pcm.resultado_esperado || '',
  urgencia:           pcm.captured_urgencia   || pcm.urgencia   || 'Normal',
  area:               pcm.area                || '',
  business_area_id:   pcm.business_area_id    || '',
  priority_id:        pcm.priority_id         || '3',
  thread_url:         pcm.thread_url          || '',
};

// --- Area del canal ---------------------------------------------------------
const baResults = $('Query Business Area').item.json.results || [];
const areaRow   = baResults[0] || null;

// Sin area configurada -> sin gate de aprobacion
if (!areaRow) {
  return [{ json: { ...reqFields, needs_approval: false, channelId, threadTs, solicitanteId, approver_ids: [] } }];
}
const areaPageId = areaRow.id;
const areaName   = areaRow.properties?.Name?.title?.[0]?.plain_text || '';

// --- Code -> pageId de capabilities -----------------------------------------
const capResults = $('Query Capabilities').item.json.results || [];
let ownCapId='', crossCapId='';
for (const c of capResults) {
  const code = c.properties?.Code?.rich_text?.[0]?.plain_text || '';
  if (code === CAP_OWN)   ownCapId   = c.id;
  if (code === CAP_CROSS) crossCapId = c.id;
}

// --- Aprobadores del area: stakeholders del area con req.approve.own --------
const areaStk = $('Query Area Stakeholders').item.json.results || [];
const approver_ids = [];
for (const s of areaStk) {
  const caps = (s.properties?.Capabilities?.relation || []).map(r => r.id);
  const slackId = s.properties?.['Slack ID']?.rich_text?.[0]?.plain_text || '';
  if (ownCapId && caps.includes(ownCapId) && slackId) approver_ids.push(slackId);
}

// --- isAutoApproved: el solicitante puede aprobar? --------------------------
const reqResults = $('Query Requester').item.json.results || [];
const reqStk = reqResults[0] || null;
let isAutoApproved = false;
if (reqStk) {
  const caps    = (reqStk.properties?.Capabilities?.relation || []).map(r => r.id);
  const reqArea = (reqStk.properties?.['Business Area']?.relation || []).map(r => r.id);
  const hasOwnHere = ownCapId && caps.includes(ownCapId) && reqArea.includes(areaPageId);
  const hasCross   = crossCapId && caps.includes(crossCapId);
  isAutoApproved = hasOwnHere || hasCross;
}

return [{ json: {
  ...reqFields,
  needs_approval: !isAutoApproved,
  approver_ids,
  area_name: areaName,
  channelId,
  threadTs,
  solicitanteId,
} }];

// Construye el mensaje de aprobacion mencionando a TODOS los aprobadores del area.
const approverIds = $json.approver_ids || [];
const mentions = approverIds.length
  ? approverIds.map(id => '<@' + id + '>').join(' ')
  : 'el responsable del area';

const body = {
  channel: $json.channelId,
  thread_ts: $json.threadTs,
  text: "Aprobación pendiente",
  attachments: [{
    text: "👋 " + mentions + ", un miembro del área envió un nuevo requerimiento. ¿Lo habilitás?",
    fallback: "¿Habilitás este requerimiento?",
    callback_id: "req_approval_" + $json.channelId + "_" + $json.threadTs.replace(".", ""),
    color: "#f59e0b",
    attachment_type: "default",
    actions: [
      { name: "approval", text: "✅ Confirmar", type: "button", value: "approve__" + $json.solicitanteId, style: "primary" },
      { name: "approval", text: "❌ Rechazar",  type: "button", value: "reject__"  + $json.solicitanteId, style: "danger"  }
    ]
  }]
};
return [{ json: { ...$json, slackBody: JSON.stringify(body) } }];

